from prometheus_client import Summary
import uuid

# Define a summary metric for HTTP requests with labels for user_id, session_id, and full request path
http_requests = Summary(
    'http_requests',
    'HTTP requests',
    ['user_id', 'session_id', 'full_request_path']
)

# Define a function to track HTTP requests with the defined labels
def track_http_request(user_id, session_id, full_request_path):
    http_requests.labels(user_id=user_id, session_id=session_id, full_request_path=full_request_path).observe()

# Define a function to create a new metric for each unique user-path combination
def create_metric(user_id, session_id, full_request_path):
    metric = Summary(
        'http_requests',
        'HTTP requests',
        ['user_id', 'session_id', 'full_request_path']
    )
    metric.labels(user_id=user_id, session_id=session_id, full_request_path=full_request_path).observe()
    return metric

# Example usage:
track_http_request('123', 'abc', '/foo')
track_http_request('456', 'def', '/bar')
create_metric('789', 'ghi', '/baz')